INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.7.101','cb','cb.adi.7','ЧБ Ади 7.101',101,'“কৃষ্ণ ‘ভজি’ তোমার হইল কোন্ সুখ? ।
মাগিয়া সে খাও, আরো বাড়ে যত দুঃখ” ॥১০১॥','‘кр̣ш̣н̣а ‘бхаджи’ тома̄ра хаила кон сукха?
ма̄гийа̄ се кха̄о, а̄ро ба̄д̣е йата дух̣кха’',NULL,NULL),('cb.adi.7.102','cb','cb.adi.7','ЧБ Ади 7.102',102,'“যোগ্য নহে এ-সব লোকের সনে বাস ।
বনে চলি’ যাঙ” বলি’ সবে ছাড়ে শ্বাস ॥১০২॥','йогйа нахе э-саба локера сане ва̄са
ване чали’ йа̄н̇а бали’ сабе чха̄д̣е ш́ва̄са',NULL,NULL),('cb.adi.7.103','cb','cb.adi.7','ЧБ Ади 7.103',103,'প্রবোধেন সবারে অদ্বৈত-মহাশয় ।
“পাইবা পরমানন্দ সবেই নিশ্চয় ॥১০৩॥','прабодхена саба̄ре адваита-маха̄ш́айа
па̄иба̄ парама̄нанда сабеи ниш́чайа',NULL,NULL),('cb.adi.7.104','cb','cb.adi.7','ЧБ Ади 7.104',104,'এবে বড় বাসোঁ মুঞি হৃদয়ে উল্লাস ।
হেন বুঝি,—‘কৃষ্ণচন্দ্র করিলা প্রকাশ’ ॥১০৪॥','эбе бад̣а ва̄сон̇ мун̃и хр̣дайе улла̄са
хена буджхи, — ‘кр̣ш̣н̣ачандра карила̄ прака̄ш́а’',NULL,NULL),('cb.adi.7.105','cb','cb.adi.7','ЧБ Ади 7.105',105,'সবে ‘কৃষ্ণ’ গাও গিয়া পরম-হরিষে ।
এথাই দেখিবা কৃষ্ণে কথেক দিবসে ॥১০৫॥','cабе ‘кр̣ш̣н̣а’ га̄о гийа̄ парама-хариш̣е
этха̄и декхиба̄ кр̣ш̣н̣е катхека дивасе',NULL,NULL),('cb.adi.7.106','cb','cb.adi.7','ЧБ Ади 7.106',106,'তোমা’ সবা লঞা হইবে কৃষ্ণের বিলাস ।
তবে সে ‘অদ্বৈত’ হঙ শুদ্ধকৃষ্ণদাস ॥১০৬॥','тома̄’ саба̄ лан̃а̄ хаибе кр̣ш̣н̣ера вила̄са
табе се ‘адваита’ хан̇а ш́уддха-кр̣ш̣н̣а-да̄са',NULL,NULL),('cb.adi.7.107','cb','cb.adi.7','ЧБ Ади 7.107',107,'কদাচিৎ যাহা না পায় শুক বা প্রহ্লাদ ।
তোমা’ সবার ভৃত্যেও পাইবে সে প্রসাদ” ॥১০৭॥','када̄чит йа̄ха̄ на̄ па̄йа ш́ука ва̄ прахла̄да
тома̄’ саба̄ра бхр̣тйео па̄ибе се праса̄да’',NULL,NULL),('cb.adi.7.108','cb','cb.adi.7','ЧБ Ади 7.108',108,'শুনি’ অদ্বৈতের অতি অমৃত-বচন ।
পরম-আনন্দে ‘হরি’ বোলে ভক্তগণ ॥১০৮॥','ш́уни’ адваитера ати-амр̣та-вачана
парама-а̄нанде ‘хари’ боле бхакта-ган̣а',NULL,NULL),('cb.adi.7.109','cb','cb.adi.7','ЧБ Ади 7.109',109,'‘হরি’ বলি’ ভক্তগণ করয়ে হুঙ্কার ।
সুখময় চিত্তবৃত্তি হইল সবার ॥১০৯॥','‘хари’ боли’ бхакта-ган̣а карайе хун̇ка̄ра
сукха-майа читта-вр̣тти хаила саба̄ра',NULL,NULL),('cb.adi.7.110','cb','cb.adi.7','ЧБ Ади 7.110',110,'শিশুসঙ্গে ক্রীড়া করে শ্রীগৌরসুন্দর ।
হরিধ্বনি শুনি’ যায় বাড়ীর ভিতর ॥১১০॥','ш́иш́у-сан̇ге крӣд̣а̄ каре ш́рӣ-гаурасундара
хари-дхвани ш́уни’ йа̄йа ба̄д̣ӣра бхитара',NULL,NULL),('cb.adi.7.111','cb','cb.adi.7','ЧБ Ади 7.111',111,'“কি কার্য্য আইলা, বাপ?” বোলে ভক্তগণে ।
প্রভু বোলে,—“তোমরা ডাকিলা মোরে কেনে?” ॥১১১॥','‘ки ка̄рйе а̄ила̄, ба̄ра?’ боле бхакта-ган̣е
прабху боле, — ‘томара̄ д̣а̄кила̄ море кене?’',NULL,NULL),('cb.adi.7.112','cb','cb.adi.7','ЧБ Ади 7.112',112,'এত বলি’ প্রভু শিশু-সঙ্গে ধাঞা যায় ।
তথাপি না জানে কেহ প্রভুর মায়ায় ॥১১২॥','эта боли’ прабху ш́иш́у-сан̇ге дха̄н̃а̄ йа̄йа
татха̄пи на̄ джа̄не кеха прабхура ма̄йа̄йа',NULL,NULL),('cb.adi.7.113','cb','cb.adi.7','ЧБ Ади 7.113',113,'যে অবধি বিশ্বরূপ হইলা বাহির ।
তদবধি প্রভু কিছু হইলা সুস্থির ॥১১৩॥','йе авадхи виш́варӯпа хаила̄ ба̄хира
тадавадхи прабху кичху хаила̄ сустхира',NULL,NULL),('cb.adi.7.114','cb','cb.adi.7','ЧБ Ади 7.114',114,'নিরবধি থাকে পিতা-মাতার সমীপে ।
দুঃখ পাসরয়ে যেন জননী-জনকে ॥১১৪॥','ниравадхи тха̄ке пита̄-ма̄та̄ра самӣпе
дух̣кха пасарайе йена джананӣ-джанаке',NULL,NULL),('cb.adi.7.115','cb','cb.adi.7','ЧБ Ади 7.115',115,'খেলা সম্বরিয়া প্রভু যত্ন করি’ পড়ে ।
তিলার্দ্ধেক পুস্তক ছাড়িয়া নাহি নড়ে ॥১১৫॥','кхела̄ самбарийа̄ прабху йатна кари’ пад̣е
тила̄рддхека пустака чха̄д̣йа̄ на̄хи над̣е',NULL,NULL),('cb.adi.7.116','cb','cb.adi.7','ЧБ Ади 7.116',116,'একবার যে সূত্র পড়িলা প্রভু যায় ।
আরবার উলটিয়া সবারে ঠেকায় ॥১১৬॥','эка-ба̄ра йе сӯтра пад̣ийа̄ прабху йа̄йа
а̄ра-ба̄ра улад̣хийа̄ саба̄ре т̣хека̄йа',NULL,NULL),('cb.adi.7.117','cb','cb.adi.7','ЧБ Ади 7.117',117,'দেখিয়া অপূর্ব্ব বুদ্ধি সবেই প্রশংসে ।
সবে বোলে,—“ধন্য পিতা-মাতা হেন বংশে” ॥১১৭॥','декхийа̄ апӯрва буддхи сабеи праш́ам̇се
сабе боле, — ‘дханйа пита̄-ма̄та̄ хена вам̇ш́е’',NULL,NULL),('cb.adi.7.118','cb','cb.adi.7','ЧБ Ади 7.118',118,'সন্তোষে কহেন সবে জগন্নাথ-স্থানে ।
“তুমি ত’ কৃতার্থ, মিশ্র, এ-হেন নন্দনে ॥১১৮॥','сантош̣е кахена сабе джаганна̄тха-стха̄не
туми та’ кр̣та̄ртха, миш́ра, э-хена нандане',NULL,NULL),('cb.adi.7.119','cb','cb.adi.7','ЧБ Ади 7.119',119,'এমত সুবুদ্ধি শিশু নাহি ত্রিভুবনে ।
বৃহস্পতি জিনিঞা হইবে অধ্যয়নে ॥১১৯॥','э-мата субуддхи ш́иш́у на̄хи трибхуване
бр̣хаспати джинин̃а̄ хаибе адхйайане',NULL,NULL),('cb.adi.7.120','cb','cb.adi.7','ЧБ Ади 7.120',120,'শুনিলেই সর্ব্ব অর্থ আপনে বাখানে ।
তান ফাঁকি বাখানিতে নারে কোন জনে” ॥১২০॥','ш́унилеи сарва артха а̄пане ва̄кха̄не
та̄’на пха̄н̇ки ва̄кха̄ните на̄ре кона джане’',NULL,NULL),('cb.adi.7.121','cb','cb.adi.7','ЧБ Ади 7.121',121,'শুনিঞা পুত্ত্রের গুণ জননী হরিষ ।
মিশ্র পুনঃ চিত্তে বড় হয় বিমরিষ ॥১২১॥','ш́унин̃а̄ путрера гун̣а джананӣ хариш̣а
миш́ра пунах̣ читте бад̣а хайа вимариш̣а',NULL,NULL),('cb.adi.7.122','cb','cb.adi.7','ЧБ Ади 7.122',122,'শচী-প্রতি বোলে জগন্নাথ মিশ্রবর ।
“এহো পুত্ত্র না রহিবে সংসার-ভিতর ॥১২২॥','ш́ачӣ-прати боле джаганна̄тха миш́ра-вара
‘ехо путра на̄ рахибе сам̇са̄ра-бхитара',NULL,NULL),('cb.adi.7.123','cb','cb.adi.7','ЧБ Ади 7.123',123,'এইমত বিশ্বরূপ পড়ি’ সর্ব্বশাস্ত্র ।
জানিলা,—‘সংসার সত্য নহে তিলমাত্র’ ॥১২৩॥','эи-мата виш́варӯпа пад̣и’ сарва-ш́а̄стра
джа̄нила̄, — ‘сам̇са̄ра сатйа нахе тила-ма̄тра’',NULL,NULL),('cb.adi.7.124','cb','cb.adi.7','ЧБ Ади 7.124',124,'সর্ব্বশাস্ত্র-মর্ম্ম জানি’ বিশ্বরূপ ধীর ।
অনিত্য সংসার হৈতে হইলা বাহির ॥১২৪॥','сарва-ш́а̄стра-марма джа̄ни’ виш́варӯпа дхӣра
анитйа сам̇са̄ра хаите хаила̄ ба̄хира',NULL,NULL),('cb.adi.7.125','cb','cb.adi.7','ЧБ Ади 7.125',125,'এহো যদি সর্ব্বশাস্ত্রে হইবে জ্ঞানবান্ ।
ছাড়িয়া সংসার-সুখ করিবে পয়ান ॥১২৫॥','эхо йади сарва-ш́а̄стре хаибе джн̃а̄нава̄н
чха̄д̣ийа̄ сам̇са̄ра-сукха карибе пайа̄на',NULL,NULL),('cb.adi.7.126','cb','cb.adi.7','ЧБ Ади 7.126',126,'এই পুত্ত্র—সবে দুইজনের জীবন ।
ইহারে না দেখিলে দুইজনের মরণ ॥১২৬॥','эи путра — сабе дуи-джанера джӣвана
иха̄ре на̄ декхиле дуи-джанера маран̣а',NULL,NULL),('cb.adi.7.127','cb','cb.adi.7','ЧБ Ади 7.127',127,'অতএব ইহার পড়িয়া কার্য্য নাই ।
মূর্খ হঞা ঘরে মোর রহুক নিমাঞি” ॥১২৭॥','атаева иха̄ра пад̣ийа̄ ка̄рйа на̄и
муркха хан̃а̄ гхаре мора рахука нима̄н̃и’',NULL,NULL),('cb.adi.7.128','cb','cb.adi.7','ЧБ Ади 7.128',128,'শচী বোলে,—“মূর্খ হইলে জীবেক কেমনে? ।
মূর্খেরে ত’কন্যাও না দিবে কোন জনে” ॥১২৮॥','ш́ачӣ боле, — ‘муркха хаиле джӣвека кемане?
муркхере та’ канйа̄о на̄ дибе кона джане’',NULL,NULL),('cb.adi.7.129','cb','cb.adi.7','ЧБ Ади 7.129',129,'মিশ্র বোলে,—“তুমি ত’ অবোধ বিপ্রসুতা! ।
হর্ত্তা কর্ত্তা ভর্ত্তা কৃষ্ণ—সবার রক্ষিতা ॥১২৯॥','миш́ра боле, ‘туми та’ абодха випра-сута̄!
харта карта̄ бхарта̄ кр̣ш̣н̣а — саба̄ра ракш̣ита̄',NULL,NULL),('cb.adi.7.130','cb','cb.adi.7','ЧБ Ади 7.130',130,'জগৎ পোষণ করে জগতের নাথ ।
‘পাণ্ডিত্যে’ পোষয়ে,—কেবা কহিলা তোমাত? ॥১৩০॥','джагат пош̣ан̣а каре джагатера на̄тха
‘па̄н̣д̣итйе пош̣айе, — кеба̄ кахила̄ тома̄та?',NULL,NULL),('cb.adi.7.131','cb','cb.adi.7','ЧБ Ади 7.131',131,'কিবা মূর্খ, কি পণ্ডিত, যাহার যেখানে ।
কন্যা লিখিয়াছে কৃষ্ণ, সে হইবে আপনে ॥১৩১॥','киба̄ муркха, ки пан̣д̣ита, йа̄ха̄ра йекха̄не
канйа̄ ликхийа̄чхе кр̣ш̣н̣а, се хаибе а̄пане',NULL,NULL),('cb.adi.7.132','cb','cb.adi.7','ЧБ Ади 7.132',132,'কুল-বিদ্যা-আদি উপলক্ষণ সকল ।
সবারে পোষয়ে কৃষ্ণ, কৃষ্ণ—সর্ব্ব-বল ॥১৩২॥','кула-видйа̄-а̄ди упалакш̣ан̣а сакала
саба̄ре пош̣айе кр̣ш̣н̣а, кр̣ш̣н̣а-сарва-бала',NULL,NULL),('cb.adi.7.133','cb','cb.adi.7','ЧБ Ади 7.133',133,'সাক্ষাতেই এই কেনে না দেখ আমাত ।
পড়িয়াও আমার ঘরে কেনে নাহি ভাত? ॥১৩৩॥','са̄кш̣а̄теи эи кене на̄ декха а̄ма̄та
пад̣ийа̄о а̄ма̄ра гхаре кене на̄хи бха̄та?',NULL,NULL),('cb.adi.7.134','cb','cb.adi.7','ЧБ Ади 7.134',134,'ভালমতে বর্ণ উচ্চারিতেও যে নারে ।
সহস্র পণ্ডিত গিয়া দেখ তার দ্বারে ॥১৩৪॥','бха̄ла-мате варн̣а учча̄ритео йе на̄ре
сахасра пан̣д̣ита гийа̄ декха та̄’ра два̄ре',NULL,NULL),('cb.adi.7.135','cb','cb.adi.7','ЧБ Ади 7.135',135,'অতএব বিদ্যা-আদি না করে পোষণ ।
কৃষ্ণ সে সবার করে পোষণ পালন ॥১৩৫॥','атаева видйа̄-а̄ди на̄ каре пош̣ан̣а
кр̣ш̣н̣а се саба̄ра каре пош̣ан̣а-па̄лана’',NULL,NULL),('cb.adi.7.136','cb','cb.adi.7','ЧБ Ади 7.136',136,'অনায়াসেন মরণং বিনা দৈন্যেন জীবনম্ ।
অনারাধিত-গোবিন্দচরণস্য কথং ভবেৎ ॥১৩৬॥','ана̄йа̄сена маран̣ам̇ вина̄ даинйена джӣванам
ана̄ра̄дхита говинда — чаран̣асйа катхам̇ бхавет',NULL,NULL),('cb.adi.7.137','cb','cb.adi.7','ЧБ Ади 7.137',137,'‘অনায়াসে মরণ, জীবন দৈন্য বিনে ।
কৃষ্ণ সেবিলে সে হয়, নহে বিদ্যা-ধনে ॥১৩৭॥','‘ана̄йа̄се маран̣а, джӣвана даинйа вине
кр̣ш̣н̣а севиле се хайа, нахе видйа̄-дхане',NULL,NULL),('cb.adi.7.138','cb','cb.adi.7','ЧБ Ади 7.138',138,'কৃষ্ণকৃপা বিনে নহে দুঃখের মোচন ।
থাকিলা বা বিদ্যা, কুল, কোটি-কোটি ধন ॥১৩৮॥','кр̣ш̣н̣а-кр̣па̄ вине нахе дух̣кхера мочана
тха̄кила ва̄ видйа̄, кула, кот̣и-кот̣и дхана',NULL,NULL),('cb.adi.7.139','cb','cb.adi.7','ЧБ Ади 7.139',139,'যার গৃহে আছয়ে উত্তম উপভোগ ।
তারে কৃষ্ণ দিয়াছেন কোন মহারোগ ॥১৩৯॥','йа̄’ра гр̣хе а̄чхайе уттама упабхога
